<template>
  <div class="named-icon-container" :style="containerStyle">
    <fa-icon :icon="icon" size="2x"/>
    <div style="width: fit-content; font-weight: 800;">
      {{ name }}
    </div>
  </div>
</template>

<script>
export default {
  name: 'NamedIcon',

  props: {
    icon: {
      type: String,
      required: true,
    },
    name: {
      type: String,
      required: true,
    },
    color: {
      type: String,
      default: 'white',
    },
    hoverColor: {
      type: String,
      default: '#fffc',
    },
  },

  computed: {
    containerStyle() {
      return {
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        width: 'fit-content',
        '--color': this.color,
        '--color-hover': this.hoverColor,
      };
    },
  },
};
</script>

<style lang="scss">
  .named-icon-container {
    color: var(--color)
  }

  .named-icon-container:hover {
    color: var(--color-hover)
  }
</style>
